    ```java
public int minimumScore(int n, int[][] roads) {
    List<Pair<Integer, Integer>>[] adj = new ArrayList[n + 1];
    for (int i = 1; i <= n; i++) {
        adj[i] = new ArrayList<>();
    }
    for (int[] road : roads) {
        adj[road[0]].add(new Pair<>(road[1], road[2]));
        adj[road[1]].add(new Pair<>(road[0], road[2]));
    }

    int INF = 1000000000;
    PriorityQueue<Pair<Integer, Integer>> pq = new PriorityQueue<>();
    pq.offer(new Pair<>(0, 1));

    int[] minDist = new int[n + 1];
    Arrays.fill(minDist, INF);
    while (!pq.isEmpty()) {
        Pair<Integer, Integer> pair = pq.poll();
        int curCity = pair.getValue();
        int curDist = pair.getKey();

        if (curCity == n) {
            return curDist;
        }

        if (curDist < minDist[curCity]) {
            minDist[curCity] = curDist;
            for (Pair<Integer, Integer> neighbor : adj[curCity]) {
                int nextCity = neighbor.getKey();
                int nextDist = Math.max(curDist, neighbor.getValue());
                if (nextDist < minDist[nextCity]) {
                    pq.offer(new Pair<>(nextDist, nextCity));
                }
            }
        }
    }

    return -1;
}
```


